        if (s === target) return [left, right];
        else if (s < target) left++;
        else right--;
    }
    return [];
}

// Palindrome check
function isPalindrome(s) {
    let l = 0, r = s.length - 1;
    while (l < r) {
        if (s[l++] !== s[r--]) return false;
    }
    return true;
}

